#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int e, m, h;
        scanf("%d %d %d", &e, &m, &h);
        int ans = 0;
        while (e > 0 && m > 0 && h > 0) {
            ans++;
            e--;
            m--;
            h--;
        }
        while (e > 1 && m > 0) {
            ans++;
            e -= 2;
            m--;
        }
        while (e > 0 && m > 1) {
            ans++;
            e--;
            m -= 2;
        }
        printf("%d\n", ans);
    }
    return 0;
}

